284→export function normalizeEnrichPayload(category: SubmissionCategory, details: SubmissionDetails): SubmissionDetails {
285→  const normalized = normalizeDetailsForCategory(category, details);
286→  if (normalized.hours && !normalized.openingHours) normalized.openingHours = String(normalized.hours);
287→  return normalized;
288→}
