 66→function parseLocation(input: unknown): SubmissionLocation | null {
 67→  if (!input || typeof input !== "object") return null;
 68→  const location = input as { latitude?: unknown; longitude?: unknown };
 69→  const latitude = typeof location.latitude === "string" ? Number(location.latitude) : (location.latitude as number);
 70→  const longitude = typeof location.longitude === "string" ? Number(location.longitude) : (location.longitude as number);
 71→  if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) return null;
 72→  return { latitude, longitude };
 73→}
 74→
 75→function hasValue(input: unknown): boolean {
 76→  if (typeof input === "string") return Boolean(input.trim());
 77→  if (typeof input === "boolean") return true;
 78→  if (typeof input === "number") return Number.isFinite(input);
 79→  if (Array.isArray(input)) return input.length > 0;
 80→  if (input && typeof input === "object") return Object.keys(input as object).length > 0;
 81→  return false;
 82→}
 83→
 84→function trimString(input: unknown, maxLen = 256): string | null {
 85→  if (typeof input !== "string") return null;
 86→  const value = input.trim();
 87→  if (!value) return null;
 88→  return value.slice(0, maxLen);
 89→}
 90→
 91→function sanitizeClientDevice(input: unknown): ClientDeviceInfo | null {
 92→  if (!input || typeof input !== "object") return null;
 93→  const raw = input as Record<string, unknown>;
 94→  const deviceId = trimString(raw.deviceId, 128);
 95→  if (!deviceId) return null;
 96→  const platform = trimString(raw.platform, 64);
 97→  const userAgent = trimString(raw.userAgent, 256);
 98→  const memory = typeof raw.deviceMemoryGb === "number" && Number.isFinite(raw.deviceMemoryGb) ? raw.deviceMemoryGb : null;
 99→  const cpu = typeof raw.hardwareConcurrency === "number" && Number.isFinite(raw.hardwareConcurrency) ? raw.hardwareConcurrency : null;
100→  const isLowEnd = raw.isLowEnd === true;
101→
102→  return {
103→    deviceId,
104→    platform: platform ?? undefined,
105→    userAgent: userAgent ?? undefined,
106→    deviceMemoryGb: memory,
107→    hardwareConcurrency: cpu,
108→    isLowEnd,
109→  };
