226→async function fetchIpLocation(ip: string): Promise<SubmissionLocation | null> {
227→  const target = `https://ipapi.co/${ip}/json/`;
228→  const controller = new AbortController();
229→  const timeout = setTimeout(() => controller.abort(), 3000);
230→  try {
231→    const res = await fetch(target, { signal: controller.signal });
232→    if (!res.ok) return null;
233→    const data = (await res.json()) as IpApiResponse;
234→    const latitude = Number(data?.latitude);
235→    const longitude = Number(data?.longitude);
236→    if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) return null;
237→    return { latitude, longitude };
238→  } catch {
239→    return null;
240→  } finally {
241→    clearTimeout(timeout);
242→  }
243→}
