283→function shouldRunFallbackFraudCheck(event: PointEvent, fraudCheck: SubmissionFraudCheck | null): boolean {
284→  const primaryUrl = typeof event.photoUrl === "string" ? event.photoUrl.trim() : "";
285→  const secondaryUrl = getSecondaryPhotoUrl(event);
286→  if (!fraudCheck) return Boolean(primaryUrl || secondaryUrl);
287→  if (primaryUrl && isPhotoMetadataEffectivelyEmpty(fraudCheck.primaryPhoto)) return true;
288→  if (secondaryUrl && isPhotoMetadataEffectivelyEmpty(fraudCheck.secondaryPhoto)) return true;
289→  return false;
