292→function mergePhotoFraudMetadata(
293→  existing: SubmissionFraudCheck["primaryPhoto"],
294→  recovered: SubmissionFraudCheck["primaryPhoto"],
295→  hasPhotoUrl: boolean,
296→): SubmissionFraudCheck["primaryPhoto"] {
297→  if (!hasPhotoUrl) return existing ?? null;
298→  if (existing && !isPhotoMetadataEffectivelyEmpty(existing)) return existing;
299→  if (recovered) return recovered;
300→  return existing ?? null;
301→}
