303→async function buildFallbackFraudCheck(
304→  event: PointEvent,
305→  existingFraudCheck: SubmissionFraudCheck | null,
306→): Promise<SubmissionFraudCheck | null> {
307→  const primaryUrl = typeof event.photoUrl === "string" ? event.photoUrl.trim() : "";
308→  const secondaryUrl = getSecondaryPhotoUrl(event);
309→  if (!primaryUrl && !secondaryUrl) return existingFraudCheck;
310→
311→  const needsPrimaryRecovery = Boolean(primaryUrl) && isPhotoMetadataEffectivelyEmpty(existingFraudCheck?.primaryPhoto);
312→  const needsSecondaryRecovery = Boolean(secondaryUrl) && isPhotoMetadataEffectivelyEmpty(existingFraudCheck?.secondaryPhoto);
313→  const primaryExtracted = needsPrimaryRecovery ? await extractPhotoMetadataFromUrl(primaryUrl) : null;
314→  const secondaryExtracted = needsSecondaryRecovery ? await extractPhotoMetadataFromUrl(secondaryUrl) : null;
315→  const recoveredPrimaryPhoto = buildPhotoFraudMetadata({
316→    extracted: primaryExtracted,
317→    submissionLocation: event.location,
318→    ipLocation: null,
319→    submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
320→    ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
321→  });
322→  const recoveredSecondaryPhoto = buildPhotoFraudMetadata({
323→    extracted: secondaryExtracted,
324→    submissionLocation: event.location,
325→    ipLocation: null,
326→    submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
327→    ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
328→  });
329→  const primaryPhoto = mergePhotoFraudMetadata(existingFraudCheck?.primaryPhoto ?? null, recoveredPrimaryPhoto, Boolean(primaryUrl));
330→  const secondaryPhoto = mergePhotoFraudMetadata(
331→    existingFraudCheck?.secondaryPhoto ?? null,
332→    recoveredSecondaryPhoto,
333→    Boolean(secondaryUrl),
334→  );
335→  if (!primaryPhoto && !secondaryPhoto) return null;
336→
337→  return buildSubmissionFraudCheck({
338→    submissionLocation: existingFraudCheck?.submissionLocation ?? event.location,
339→    effectiveLocation: existingFraudCheck?.effectiveLocation ?? event.location,
340→    ipLocation: existingFraudCheck?.ipLocation ?? null,
341→    primaryPhoto,
342→    secondaryPhoto,
343→    submissionMatchThresholdKm: existingFraudCheck?.submissionMatchThresholdKm ?? SUBMISSION_PHOTO_MATCH_KM,
344→    ipMatchThresholdKm: existingFraudCheck?.ipMatchThresholdKm ?? IP_PHOTO_MATCH_KM,
345→  });
346→}
