395→async function buildCombinedEvents(): Promise<PointEvent[]> {
396→  const pointEvents = (await getPointEvents()).map(stripInlinePhotoData);
397→  const legacySubmissions = await getLegacySubmissions();
398→  const merged = mergePointEventsWithLegacy(pointEvents, legacySubmissions);
399→  const seenExternalIds = new Set(
400→    merged
401→      .map((event) => (typeof event.externalId === "string" ? event.externalId.trim() : ""))
402→      .filter((value) => value.length > 0),
403→  );
404→  const seenPointIds = new Set(merged.map((event) => event.pointId));
405→  for (const seedEvent of BONAMOUSSADI_CURATED_SEED_EVENTS) {
406→    const externalId = typeof seedEvent.externalId === "string" ? seedEvent.externalId.trim() : "";
407→    if (externalId && seenExternalIds.has(externalId)) continue;
408→    if (seenPointIds.has(seedEvent.pointId)) continue;
409→    merged.push(seedEvent);
410→    if (externalId) seenExternalIds.add(externalId);
411→    seenPointIds.add(seedEvent.pointId);
412→  }
413→  return merged;
414→}
