416→export async function GET(request: Request): Promise<Response> {
417→  const auth = await requireUser(request);
418→  const authContext = toSubmissionAuthContext(auth);
419→  const url = new URL(request.url);
420→  const view = url.searchParams.get("view");
421→  const lat = url.searchParams.get("lat");
422→  const lng = url.searchParams.get("lng");
423→  const radius = url.searchParams.get("radius");
424→  const requestedScope = normalizeMapScope(url.searchParams.get("scope"));
425→  const canUseExpandedScope = requestedScope !== "bonamoussadi";
426→  if (canUseExpandedScope && !authContext) return errorResponse("Unauthorized", 401);
427→  if (canUseExpandedScope && !authContext.isAdmin) return errorResponse("Forbidden", 403);
428→  const effectiveScope = canUseExpandedScope ? requestedScope : "bonamoussadi";
429→  const canUsePublicCache = !authContext && !canUseExpandedScope;
430→
431→  try {
432→    const allEvents = await buildCombinedEvents();
433→    const scopedEvents = allEvents.filter((event) => {
434→      if (effectiveScope === "global") return true;
435→      if (effectiveScope === "cameroon") return isWithinCameroon(event.location);
436→      return isWithinBonamoussadi(event.location);
437→    });
438→
439→    if (view === "events") {
440→      if (!authContext) {
441→        return jsonResponse(redactEventUserIds(scopedEvents), {
442→          status: 200,
443→          headers: {
444→            "cache-control": PUBLIC_READ_CACHE_CONTROL,
445→          },
446→        });
447→      }
448→      const responseEvents = filterEventsForViewer(scopedEvents, authContext);
449→      return jsonResponse(responseEvents, { status: 200 });
450→    }
451→
452→    if (view === "admin_events") {
453→      const adminAccess = resolveAdminViewAccess(authContext);
454→      if (adminAccess === "unauthorized") return errorResponse("Unauthorized", 401);
455→      if (adminAccess === "forbidden") return errorResponse("Forbidden", 403);
456→      const adminEvents = await buildAdminSubmissionEvents(scopedEvents);
457→      return jsonResponse(adminEvents, { status: 200 });
458→    }
459→
460→    let projected = projectPointsFromEvents(scopedEvents);
461→
462→    if (lat && lng && radius) {
463→      const latitude = Number(lat);
464→      const longitude = Number(lng);
465→      const radiusKm = Number(radius);
466→      if (Number.isFinite(latitude) && Number.isFinite(longitude) && Number.isFinite(radiusKm)) {
467→        projected = projected.filter((point) => haversineKm(point.location, { latitude, longitude }) <= radiusKm);
468→      }
469→    }
470→
471→    return jsonResponse(projected, {
472→      status: 200,
473→      headers: canUsePublicCache
474→        ? {
475→            "cache-control": PUBLIC_READ_CACHE_CONTROL,
476→          }
477→        : undefined,
478→    });
479→  } catch (error) {
480→    if (isStorageUnavailableError(error)) {
481→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
482→    }
483→    throw error;
484→  }
485→}
