487→export async function POST(request: Request): Promise<Response> {
488→  const auth = await requireUser(request);
489→  if (!auth) return errorResponse("Unauthorized", 401);
490→  const authContext = toSubmissionAuthContext(auth);
491→  const isAdminUser = authContext?.isAdmin === true;
492→
493→  let body: SubmissionInput;
494→  try {
495→    body = (await request.json()) as SubmissionInput;
496→  } catch {
497→    return errorResponse("Invalid JSON body", 400);
498→  }
499→
500→  const category = normalizeCategory(body?.category as string | undefined);
501→  if (!category || !allowedCategories.includes(category)) {
502→    return errorResponse("Invalid category", 400);
503→  }
504→
505→  const eventType = normalizeEventType(body?.eventType);
506→  const location = parseLocation(body?.location);
507→  const details = normalizeEnrichPayload(
508→    category,
509→    body?.details && typeof body.details === "object" ? ({ ...(body.details as SubmissionDetails) } as SubmissionDetails) : {},
510→  );
511→  const requestUserAgent = trimString(request.headers.get("user-agent"), 256);
512→  const clientDevice = sanitizeClientDevice((details as Record<string, unknown>).clientDevice);
513→  if (clientDevice) {
514→    if (!clientDevice.userAgent && requestUserAgent) clientDevice.userAgent = requestUserAgent;
515→    details.clientDevice = clientDevice;
516→  } else if ("clientDevice" in details) {
517→    delete details.clientDevice;
518→  }
519→
520→  const imageBase64 = body?.imageBase64 as string | undefined;
521→  if (!imageBase64) return errorResponse("Photo is required", 400);
522→  const parsedPhoto = parseImagePayload(imageBase64);
523→  if (!parsedPhoto) return errorResponse("Invalid photo format", 400);
524→  if (parsedPhoto.imageBuffer.byteLength > MAX_IMAGE_BYTES) {
525→    return errorResponse(`Photo exceeds maximum size of ${Math.round(MAX_IMAGE_BYTES / (1024 * 1024))}MB`, 400);
526→  }
527→
528→  const ipLocation = await getIpLocation(request);
529→  const clientExif = (body as unknown as Record<string, unknown>)?.clientExif as ClientExifData | null | undefined;
530→  let photoLocation: SubmissionLocation | null = null;
531→  let primaryPhotoMetadata: Awaited<ReturnType<typeof extractPhotoMetadata>> | null = null;
532→
533→  try {
534→    primaryPhotoMetadata = await extractPhotoMetadata(parsedPhoto.imageBuffer, {
535→      source: "upload_buffer",
536→      mime: parsedPhoto.mime,
537→      ext: parsedPhoto.ext,
538→      byteLength: parsedPhoto.imageBuffer.byteLength,
539→    });
540→    primaryPhotoMetadata = applyClientExifFallback(primaryPhotoMetadata, clientExif);
541→    if (primaryPhotoMetadata.gps) {
542→      photoLocation = primaryPhotoMetadata.gps;
543→      if (location) {
544→        const distance = haversineKm(location, photoLocation);
545→        if (distance > SUBMISSION_PHOTO_MATCH_KM) return errorResponse("Photo GPS coordinates do not match submission location", 400);
546→      }
547→      if (ipLocation) {
548→        const distance = haversineKm(ipLocation, photoLocation);
549→        if (distance > IP_PHOTO_MATCH_KM) return errorResponse("Photo location does not match IP location", 400);
550→      }
551→    } else if (!location && !ipLocation) {
552→      return errorResponse("Photo is missing GPS metadata", 400);
553→    }
554→  } catch {
555→    primaryPhotoMetadata = {
556→      gps: null,
557→      capturedAt: null,
558→      deviceMake: null,
559→      deviceModel: null,
560→      exifStatus: "parse_error",
561→      exifReason: `Unexpected EXIF extraction failure (mime=${parsedPhoto.mime}; ext=${parsedPhoto.ext}; bytes=${parsedPhoto.imageBuffer.byteLength})`,
562→      exifSource: "upload_buffer",
563→    };
564→    primaryPhotoMetadata = applyClientExifFallback(primaryPhotoMetadata, clientExif);
565→    if (!primaryPhotoMetadata.gps && !location && !ipLocation) {
566→      return errorResponse("Unable to read photo GPS metadata", 400);
567→    }
568→    if (primaryPhotoMetadata.gps) {
569→      photoLocation = primaryPhotoMetadata.gps;
570→    }
571→  }
572→
573→  const finalLocation = photoLocation ?? location ?? ipLocation;
574→  if (!finalLocation) return errorResponse("Missing or invalid location", 400);
575→  if (!isAdminUser && !isWithinBonamoussadi(finalLocation)) {
576→    return errorResponse(
577→      `Location outside Bonamoussadi bounds (${BONAMOUSSADI_BOUNDS.south},${BONAMOUSSADI_BOUNDS.west})-(${BONAMOUSSADI_BOUNDS.north},${BONAMOUSSADI_BOUNDS.east})`,
578→      400,
579→    );
580→  }
581→
582→  try {
583→    const existingEvents = await buildCombinedEvents();
584→    const projectedExisting = projectPointsFromEvents(existingEvents);
585→    let pointId = typeof body.pointId === "string" && body.pointId.trim() ? body.pointId.trim() : crypto.randomUUID();
586→
587→    if (eventType === "CREATE_EVENT") {
588→      const createError = validateCreatePayload(category, details);
589→      if (createError) return errorResponse(createError, 400);
590→    } else {
591→      if (!body.pointId || typeof body.pointId !== "string" || !body.pointId.trim()) {
592→        return errorResponse("pointId is required for ENRICH_EVENT", 400);
593→      }
594→      pointId = body.pointId.trim();
595→      const target = projectedExisting.find((point) => point.pointId === pointId);
596→      if (!target) return errorResponse("Target point not found", 404);
597→      if (target.category !== category) return errorResponse("Category mismatch for target point", 400);
598→
599→      const submittedEntries = Object.entries(details).filter(([, value]) => hasValue(value));
600→      const allowedGaps = new Set(target.gaps);
601→      const filteredEntries = submittedEntries.filter(([field]) => {
602→        const canonical =
603→          field === "hours"
604→            ? "openingHours"
605→            : field === "merchantId"
606→              ? "merchantIdByProvider"
607→              : field === "hasCashAvailable"
608→                ? "hasMin50000XafAvailable"
609→                : field;
610→        return isEnrichFieldAllowed(category, canonical) && allowedGaps.has(canonical);
611→      });
612→      if (!filteredEntries.length) {
613→        return errorResponse("ENRICH_EVENT must include at least one currently missing field", 400);
614→      }
615→      const filteredDetails: SubmissionDetails = {};
616→      for (const [key, value] of filteredEntries) {
617→        filteredDetails[key] = value;
618→      }
619→      Object.assign(details, filteredDetails);
620→      for (const key of Object.keys(details)) {
621→        if (!Object.prototype.hasOwnProperty.call(filteredDetails, key)) {
622→          delete details[key];
623→        }
624→      }
625→      if (clientDevice) {
626→        details.clientDevice = clientDevice;
627→      }
628→    }
629→
630→    const eventId = crypto.randomUUID();
631→    let photoUrl: string | undefined;
632→    try {
633→      photoUrl = await uploadSubmissionPhoto(eventId, parsedPhoto.imageBuffer, parsedPhoto.mime, parsedPhoto.ext);
634→    } catch (error) {
635→      const raw = error instanceof Error ? error.message : String(error);
636→      const lower = raw.toLowerCase();
637→      if (lower.includes("blob") && lower.includes("token")) return errorResponse("Blob storage is not configured", 500);
638→      return errorResponse("Unable to store photo", 500);
639→    }
640→    details.hasPhoto = true;
641→
642→    let secondaryPhotoMetadata: Awaited<ReturnType<typeof extractPhotoMetadata>> | null = null;
643→    const secondImageBase64 = body?.secondImageBase64 as string | undefined;
644→    if (secondImageBase64) {
645→      const parsedSecondPhoto = parseImagePayload(secondImageBase64);
646→      if (!parsedSecondPhoto) return errorResponse("Invalid photo format", 400);
647→      if (parsedSecondPhoto.imageBuffer.byteLength > MAX_IMAGE_BYTES) {
648→        return errorResponse(`Photo exceeds maximum size of ${Math.round(MAX_IMAGE_BYTES / (1024 * 1024))}MB`, 400);
649→      }
650→
651→      try {
652→        secondaryPhotoMetadata = await extractPhotoMetadata(parsedSecondPhoto.imageBuffer, {
653→          source: "upload_buffer",
654→          mime: parsedSecondPhoto.mime,
655→          ext: parsedSecondPhoto.ext,
656→          byteLength: parsedSecondPhoto.imageBuffer.byteLength,
657→        });
658→      } catch {
659→        secondaryPhotoMetadata = {
660→          gps: null,
661→          capturedAt: null,
662→          deviceMake: null,
663→          deviceModel: null,
664→          exifStatus: "parse_error",
665→          exifReason: `Unexpected EXIF extraction failure (mime=${parsedSecondPhoto.mime}; ext=${parsedSecondPhoto.ext}; bytes=${parsedSecondPhoto.imageBuffer.byteLength})`,
666→          exifSource: "upload_buffer",
667→        };
668→      }
669→
670→      try {
671→        const secondPhotoUrl = await uploadSubmissionPhoto(
672→          `${eventId}-second`,
673→          parsedSecondPhoto.imageBuffer,
674→          parsedSecondPhoto.mime,
675→          parsedSecondPhoto.ext,
676→        );
677→        details.secondPhotoUrl = secondPhotoUrl;
678→        details.hasSecondaryPhoto = true;
679→      } catch {
680→        return errorResponse("Unable to store photo", 500);
681→      }
682→    }
683→
684→    const primaryPhotoFraud = buildPhotoFraudMetadata({
685→      extracted: primaryPhotoMetadata,
686→      submissionLocation: location,
687→      ipLocation,
688→      submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
689→      ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
690→    });
691→    const secondaryPhotoFraud = buildPhotoFraudMetadata({
692→      extracted: secondaryPhotoMetadata,
693→      submissionLocation: location,
694→      ipLocation,
695→      submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
696→      ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
697→    });
698→    details.fraudCheck = buildSubmissionFraudCheck({
699→      submissionLocation: location,
700→      effectiveLocation: finalLocation,
701→      ipLocation,
702→      primaryPhoto: primaryPhotoFraud,
703→      secondaryPhoto: secondaryPhotoFraud,
704→      submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
705→      ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
706→    });
707→
708→    const now = new Date().toISOString();
709→    const newEvent: PointEvent = {
710→      id: eventId,
711→      pointId,
712→      eventType,
713→      userId: auth.id,
714→      category,
715→      location: finalLocation,
716→      details,
717→      photoUrl,
718→      createdAt: now,
719→      source: typeof details.source === "string" ? details.source : undefined,
720→      externalId: typeof details.externalId === "string" ? details.externalId : undefined,
721→    };
722→
723→    await insertPointEvent(newEvent);
724→
725→    const exifDeviceMake = primaryPhotoMetadata?.deviceMake ?? null;
726→    const exifDeviceModel = primaryPhotoMetadata?.deviceModel ?? null;
727→    const logPayload = {
728→      eventId,
729→      userId: auth.id,
730→      category,
731→      deviceId: clientDevice?.deviceId ?? null,
732→      clientPlatform: clientDevice?.platform ?? null,
733→      clientUserAgent: clientDevice?.userAgent ?? requestUserAgent ?? null,
734→      clientMemoryGb: clientDevice?.deviceMemoryGb ?? null,
735→      clientCpuCores: clientDevice?.hardwareConcurrency ?? null,
736→      clientIsLowEnd: clientDevice?.isLowEnd ?? null,
737→      exifDeviceMake,
738→      exifDeviceModel,
739→    };
740→    if (process.env.NODE_ENV !== "production") {
741→      console.info("[SUBMISSION_DEVICE]", JSON.stringify(logPayload));
742→    }
743→
744→    const profile = await getUserProfile(auth.id);
745→    if (profile) {
746→      profile.XP = (profile.XP ?? 0) + BASE_EVENT_XP;
747→      await upsertUserProfile(auth.id, profile);
748→    }
749→
750→    return jsonResponse(newEvent, { status: 201 });
751→  } catch (error) {
752→    if (isStorageUnavailableError(error)) {
753→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
754→    }
755→    throw error;
756→  }
757→}
