 26→const Profile: React.FC<Props> = ({ onBack, onSettings, onRedeem, language }) => {
 27→  const t = (en: string, fr: string) => (language === 'fr' ? fr : en);
 28→  const [profile, setProfile] = useState<UserProfile | null>(null);
 29→  const [isLoading, setIsLoading] = useState(true);
 30→  const [loadError, setLoadError] = useState('');
