 32→  const [history, setHistory] = useState<Array<{ id: string; date: string; location: string; type: string; xp: number }>>([]);
 33→  const [syncErrors, setSyncErrors] = useState<SyncErrorRecord[]>([]);
 34→  const [isLoadingSyncErrors, setIsLoadingSyncErrors] = useState(true);
 35→  const [isClearingSyncErrors, setIsClearingSyncErrors] = useState(false);
 36→  const [syncErrorActionError, setSyncErrorActionError] = useState('');
 37→  const normalizeMapScope = (value: unknown, isAdminMode: boolean): MapScope => {
 38→    if (isAdminMode) return 'global';
 39→    if (value === 'cameroon' || value === 'global') return value;
 40→    return 'bonamoussadi';
 41→  };
 42→  const activeMapScope = normalizeMapScope(profile?.mapScope, Boolean(profile?.isAdmin));
 43→  const isMapUnlocked = activeMapScope !== 'bonamoussadi';
 44→
 45→  const formatHistoryDate = (iso: string) => {
 46→    const date = new Date(iso);
 47→    if (Number.isNaN(date.getTime())) return t('Unknown', 'Inconnu');
 48→
 49→    const now = new Date();
 50→    const sameDay = now.toDateString() === date.toDateString();
 51→    const yesterday = new Date(now);
 52→    yesterday.setDate(now.getDate() - 1);
 53→    const isYesterday = yesterday.toDateString() === date.toDateString();
 54→    const time = date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
 55→
 56→    if (sameDay) return language === 'fr' ? `Aujourd'hui • ${time}` : `Today • ${time}`;
 57→    if (isYesterday) return language === 'fr' ? `Hier • ${time}` : `Yesterday • ${time}`;
 58→    return `${date.toLocaleDateString([], { month: 'short', day: '2-digit' })} • ${time}`;
 59→  };
 60→
 61→  const submissionToHistory = (submission: PointEvent) => {
 62→    const details = (submission.details ?? {}) as Record<string, unknown>;
 63→    const siteName = typeof details.siteName === 'string' ? details.siteName : typeof details.name === 'string' ? details.name : null;
 64→    const locationLabel = siteName || `GPS: ${submission.location.latitude.toFixed(4)}°, ${submission.location.longitude.toFixed(4)}°`;
 65→    const typeLabel =
 66→      submission.category === 'fuel_station'
 67→        ? t('Fuel Station', 'Station-service')
 68→        : submission.category === 'pharmacy'
 69→          ? t('Pharmacy', 'Pharmacie')
 70→          : t('Mobile Money Kiosk', 'Kiosque mobile money');
 71→    const rawXp = details.xpAwarded;
 72→    const xpAwarded = typeof rawXp === 'number' && Number.isFinite(rawXp) ? rawXp : 5;
 73→
 74→    return {
 75→      id: submission.id,
 76→      date: formatHistoryDate(submission.createdAt),
 77→      location: locationLabel,
 78→      type: typeLabel,
 79→      xp: xpAwarded
 80→    };
 81→  };
 82→
 83→  const categoryLabel = (category: SyncErrorRecord['payloadSummary']['category']) => {
