108→
109→          const ownSubmissions = submissions
110→            .filter((submission) => (typeof submission.userId === 'string' ? submission.userId.toLowerCase().trim() : '') === userId)
111→            .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
