115→          const latest = ownSubmissions[0];
116→          if (latest) {
117→            const details = (latest.details ?? {}) as Record<string, unknown>;
118→            const siteName = typeof details.siteName === 'string' ? details.siteName : typeof details.name === 'string' ? details.name : null;
119→            setUserLocation(siteName || `GPS ${latest.location.latitude.toFixed(4)}°, ${latest.location.longitude.toFixed(4)}°`);
120→          } else {
