117→
118→        const completed = safePoints.filter((point) => Array.isArray(point.gaps) && point.gaps.length === 0).length;
119→        const completion = safePoints.length > 0 ? Math.round((completed / safePoints.length) * 100) : 0;
120→        setCompletionRate(completion);
121→
122→        const now = Date.now();
123→        const activeWindowMs = 30 * 24 * 60 * 60 * 1000;
124→        const activeUsers = new Set(
125→          safeEvents
126→            .filter((event) => {
127→              const createdAt = new Date(event.createdAt).getTime();
128→              return Number.isFinite(createdAt) && now - createdAt <= activeWindowMs;
129→            })
130→            .map((event) => event.userId)
131→            .filter((userId) => typeof userId === 'string' && userId.trim().length > 0)
132→        );
