134→
135→        const categoryCounts: Record<SubmissionCategory, number> = {
136→          pharmacy: 0,
137→          fuel_station: 0,
138→          mobile_money: 0
139→        };
140→        for (const event of safeEvents) {
141→          if (event.category in categoryCounts) categoryCounts[event.category] += 1;
142→        }
143→        setCategoryData([
144→          { name: categoryLabel('pharmacy'), value: categoryCounts.pharmacy, color: '#2f855a' },
145→          { name: categoryLabel('fuel_station'), value: categoryCounts.fuel_station, color: '#0f2b46' },
146→          { name: categoryLabel('mobile_money'), value: categoryCounts.mobile_money, color: '#c86b4a' }
147→        ]);
148→
149→        const categories: SubmissionCategory[] = ['pharmacy', 'fuel_station', 'mobile_money'];
150→        const bucketsPerCategory = categories.map(() => [0, 0, 0, 0]);
151→        const heatWindowMs = 24 * 60 * 60 * 1000;
152→        for (const event of safeEvents) {
153→          const timestamp = new Date(event.createdAt).getTime();
154→          if (!Number.isFinite(timestamp) || now - timestamp > heatWindowMs || timestamp > now) continue;
155→          const categoryIndex = categories.indexOf(event.category);
156→          if (categoryIndex === -1) continue;
157→          const bucketIndex = Math.max(0, Math.min(3, Math.floor(new Date(timestamp).getHours() / 6)));
158→          bucketsPerCategory[categoryIndex][bucketIndex] += 1;
159→        }
160→
161→        const maxValue = Math.max(...bucketsPerCategory.flat(), 0);
162→        const toHeatLevel = (value: number): HeatLevel => {
163→          if (maxValue <= 0 || value <= 0) return 'Low';
164→          const ratio = value / maxValue;
165→          if (ratio >= 0.67) return 'High';
166→          if (ratio >= 0.34) return 'Medium';
167→          return 'Low';
168→        };
169→
170→        setHeatmap(
171→          bucketsPerCategory.map((row) => row.map((value) => toHeatLevel(value)))
172→        );
173→      } catch {
