134→   134→   134→function parseDeviceFromUserAgent(): { make: string | null; model: string | null } {
135→   135→   135→  const ua = navigator.userAgent;
136→   136→   136→  // iPhone detection
137→   137→   137→  const iphoneMatch = ua.match(/iPhone/);
138→   138→   138→  if (iphoneMatch) return { make: 'Apple', model: 'iPhone' };
