148→   148→   148→async function extractClientExif(
149→   149→   149→  file: File,
150→   150→   150→  deviceLocation: { latitude: number; longitude: number } | null,
151→   151→   151→): Promise<ClientExifData | null> {
152→   152→   152→  // Step 1: Try extracting EXIF from the raw file (works on Android, some iOS versions)
153→   153→   153→  let lat: number | null = null;
154→   154→   154→  let lng: number | null = null;
155→   155→   155→  let capturedAt: string | null = null;
156→   156→   156→  let deviceMake: string | null = null;
157→   157→   157→  let deviceModel: string | null = null;
158→   158→   158→
159→   159→   159→  try {
160→   160→   160→    const buffer = await file.arrayBuffer();
161→   161→   161→    const [exifData, gpsData] = await Promise.all([
162→   162→   162→      exifr.parse(buffer, { gps: true, exif: true, tiff: true, pick: [
163→   163→   163→        'latitude', 'longitude', 'GPSLatitude', 'GPSLongitude',
164→   164→   164→        'DateTimeOriginal', 'DateTimeDigitized', 'CreateDate', 'ModifyDate',
165→   165→   165→        'Make', 'Model',
166→   166→   166→      ] }).catch(() => null),
167→   167→   167→      exifr.gps(buffer).catch(() => null),
168→   168→   168→    ]);
169→   169→   169→    const merged = { ...(exifData ?? {}), ...(gpsData ?? {}) } as Record<string, unknown>;
170→   170→   170→    lat = typeof merged.latitude === 'number' ? merged.latitude : null;
171→   171→   171→    lng = typeof merged.longitude === 'number' ? merged.longitude : null;
172→   172→   172→    const rawDate = merged.DateTimeOriginal ?? merged.DateTimeDigitized ?? merged.CreateDate ?? merged.ModifyDate;
173→   173→   173→    if (rawDate instanceof Date) {
174→   174→   174→      capturedAt = rawDate.toISOString();
175→   175→   175→    } else if (typeof rawDate === 'string' && rawDate.trim()) {
176→   176→   176→      const m = rawDate.match(/^(\d{4}):(\d{2}):(\d{2})\s+(\d{2}):(\d{2}):(\d{2})/);
177→   177→   177→      capturedAt = m ? `${m[1]}-${m[2]}-${m[3]}T${m[4]}:${m[5]}:${m[6]}` : rawDate;
178→   178→   178→    }
179→   179→   179→    deviceMake = typeof merged.Make === 'string' ? merged.Make : null;
180→   180→   180→    deviceModel = typeof merged.Model === 'string' ? merged.Model : null;
181→   181→   181→  } catch {
182→   182→   182→    // EXIF parsing failed entirely -- fall through to device fallback
183→   183→   183→  }
184→   184→   184→
185→   185→   185→  // Step 2: Fill gaps with browser APIs (critical for iOS which strips EXIF from <input capture>)
186→   186→   186→  if (lat == null && lng == null && deviceLocation) {
187→   187→   187→    lat = deviceLocation.latitude;
188→   188→   188→    lng = deviceLocation.longitude;
189→   189→   189→  }
190→   190→   190→  if (!capturedAt) {
191→   191→   191→    capturedAt = new Date().toISOString();
192→   192→   192→  }
193→   193→   193→  if (!deviceMake && !deviceModel) {
194→   194→   194→    const parsed = parseDeviceFromUserAgent();
195→   195→   195→    deviceMake = parsed.make;
196→   196→   196→    deviceModel = parsed.model;
197→   197→   197→  }
198→   198→   198→
199→   199→   199→  if (lat == null && lng == null && !capturedAt && !deviceMake && !deviceModel) return null;
200→   200→   200→  return { latitude: lat, longitude: lng, capturedAt, deviceMake, deviceModel };
201→   201→   201→}
