387→   387→   387→    // Keep original capture when possible so EXIF (GPS/time/device) reaches server-side forensics.
388→   388→   388→    if (file.size <= MAX_SUBMISSION_IMAGE_BYTES) {
389→   389→   389→      return await readAsDataUrl(file);
390→   390→   390→    }
391→   391→   391→
392→   392→   392→    const loadImage = (objectUrl: string) =>
393→   393→   393→      new Promise<HTMLImageElement>((resolve, reject) => {
394→   394→   394→        const img = new Image();
395→   395→   395→        img.onload = () => resolve(img);
396→   396→   396→        img.onerror = () => reject(new Error('Unable to decode image.'));
397→   397→   397→        img.src = objectUrl;
398→   398→   398→      });
399→   399→   399→
400→   400→   400→    const objectUrl = URL.createObjectURL(file);
401→   401→   401→    try {
402→   402→   402→      const img = await loadImage(objectUrl);
403→   403→   403→      const maxDimension = Math.max(img.width, img.height);
404→   404→   404→      const scale = maxDimension > MAX_UPLOAD_DIMENSION ? MAX_UPLOAD_DIMENSION / maxDimension : 1;
405→   405→   405→      const width = Math.max(1, Math.round(img.width * scale));
406→   406→   406→      const height = Math.max(1, Math.round(img.height * scale));
407→   407→   407→      const canvas = document.createElement('canvas');
408→   408→   408→      canvas.width = width;
409→   409→   409→      canvas.height = height;
410→   410→   410→      const ctx = canvas.getContext('2d');
411→   411→   411→      if (!ctx) {
412→   412→   412→        return await readAsDataUrl(file);
413→   413→   413→      }
414→   414→   414→      ctx.drawImage(img, 0, 0, width, height);
415→   415→   415→      const quality = isLowEndDevice ? IMAGE_QUALITY_LOW_END : IMAGE_QUALITY_DEFAULT;
416→   416→   416→      const compressed = canvas.toDataURL('image/jpeg', quality);
417→   417→   417→      return await preserveJpegExif(file, compressed);
418→   418→   418→    } catch {
419→   419→   419→      return await readAsDataUrl(file);
420→   420→   420→    } finally {
421→   421→   421→      URL.revokeObjectURL(objectUrl);
422→   422→   422→    }
423→   423→   423→  };
