# Vertical Registry Refactoring Plan

## 1. Registry Data Structure: `shared/verticals.ts`

This is the single source of truth. Here is the exact shape:

```typescript
// shared/verticals.ts

export type SubmissionCategory = string; // widen from union -- backward compatible
export type FieldInputType = 'text' | 'toggle' | 'select' | 'multi-select' | 'number';

export interface FieldDef {
  key: string;                         // e.g. "name", "isOpenNow", "providers"
  inputType: FieldInputType;
  label: { en: string; fr: string };
  options?: string[];                  // for select / multi-select
  presets?: string[];                  // for text with quick-pick (e.g. opening hours)
}

export interface VerticalConfig {
  // Identity
  category: string;                    // DB value: "pharmacy", "fuel_station", etc.
  enumKey: string;                     // UI enum key: "PHARMACY", "FUEL", "MOBILE_MONEY"

  // Display
  label: { en: string; fr: string };
  labelPlural: { en: string; fr: string };
  icon: string;                        // lucide icon name: "pill", "fuel", "landmark"
  color: string;                       // hex: "#2f855a"
  bgClass: string;                     // tailwind bg for selected state: "bg-[#eaf3ee]"
  borderClass: string;                 // tailwind border for selected state
  textClass: string;                   // tailwind text for selected state

  // Field schema
  createFields: FieldDef[];            // fields shown on CREATE form
  createRequiredKeys: string[];        // keys that must have values for CREATE
  enrichableKeys: string[];            // keys tracked as gaps / allowed for ENRICH

  // Normalization
  availabilityField?: string;          // which boolean field drives High/Low/Out
  availabilityInvertLogic?: boolean;   // true = "out" means false (default behavior)

  // Field aliases (server-side normalization)
  fieldAliases?: Record<string, string>; // e.g. { "hasCashAvailable": "hasMin50000XafAvailable" }
}

// --- THE REGISTRY ---
export const VERTICALS: Record<string, VerticalConfig> = {
  pharmacy: {
    category: 'pharmacy',
    enumKey: 'PHARMACY',
    label: { en: 'Pharmacy', fr: 'Pharmacie' },
    labelPlural: { en: 'Pharmacies', fr: 'Pharmacies' },
    icon: 'pill',
    color: '#2f855a',
    bgClass: 'bg-[#eaf3ee]',
    borderClass: 'border-[#2f855a]',
    textClass: 'text-[#2f855a]',
    createFields: [
      { key: 'name', inputType: 'text', label: { en: 'Pharmacy name', fr: 'Nom de la pharmacie' } },
      { key: 'isOpenNow', inputType: 'toggle', label: { en: 'Open now', fr: 'Ouvert maintenant' } },
      { key: 'openingHours', inputType: 'text', label: { en: 'Opening hours', fr: "Heures d'ouverture" }, presets: ['08:00 - 20:00', '09:00 - 19:00', '24/7'] },
    ],
    createRequiredKeys: ['name', 'isOpenNow'],
    enrichableKeys: ['openingHours', 'isOpenNow', 'isOnDuty'],
    availabilityField: 'isOpenNow',
  },
  fuel_station: {
    category: 'fuel_station',
    enumKey: 'FUEL',
    label: { en: 'Fuel Station', fr: 'Station-service' },
    labelPlural: { en: 'Fuel Stations', fr: 'Stations-service' },
    icon: 'fuel',
    color: '#0f2b46',
    bgClass: 'bg-[#e7eef4]',
    borderClass: 'border-[#0f2b46]',
    textClass: 'text-[#0f2b46]',
    createFields: [
      { key: 'name', inputType: 'text', label: { en: 'Fuel station name', fr: 'Nom de la station-service' } },
      { key: 'hasFuelAvailable', inputType: 'toggle', label: { en: 'Fuel available', fr: 'Carburant disponible' } },
      { key: 'fuelTypes', inputType: 'multi-select', label: { en: 'Fuel types', fr: 'Types de carburant' }, options: ['Super', 'Diesel', 'Gas'] },
      // ... etc
    ],
    createRequiredKeys: ['name', 'hasFuelAvailable'],
    enrichableKeys: ['fuelTypes', 'pricesByFuel', 'quality', 'paymentMethods', 'openingHours', 'hasFuelAvailable'],
    availabilityField: 'hasFuelAvailable',
  },
  mobile_money: {
    category: 'mobile_money',
    enumKey: 'MOBILE_MONEY',
    label: { en: 'Mobile Money Kiosk', fr: 'Kiosque mobile money' },
    labelPlural: { en: 'Mobile Money Kiosks', fr: 'Kiosques mobile money' },
    icon: 'landmark',
    color: '#1f2933',
    bgClass: 'bg-gray-100',
    borderClass: 'border-[#1f2933]',
    textClass: 'text-gray-700',
    createFields: [
      { key: 'providers', inputType: 'multi-select', label: { en: 'Providers', fr: 'Operateurs' }, options: ['MTN', 'Orange', 'Airtel'] },
      { key: 'openingHours', inputType: 'text', label: { en: 'Opening hours', fr: "Heures d'ouverture" }, presets: ['08:00 - 20:00', '09:00 - 19:00', '24/7'] },
      { key: 'paymentMethods', inputType: 'multi-select', label: { en: 'Payment methods', fr: 'Moyens de paiement' }, options: ['Cash', 'Mobile Money', 'Card'] },
    ],
    createRequiredKeys: ['providers'],
    enrichableKeys: ['merchantIdByProvider', 'paymentMethods', 'openingHours', 'providers'],
    availabilityField: 'hasMin50000XafAvailable',
    fieldAliases: { hasCashAvailable: 'hasMin50000XafAvailable' },
  },
};

// --- HELPER FUNCTIONS (used across client + server) ---
export const VERTICAL_LIST: VerticalConfig[] = Object.values(VERTICALS);
export const ALL_CATEGORIES: string[] = VERTICAL_LIST.map(v => v.category);

export function getVertical(category: string): VerticalConfig | undefined {
  return VERTICALS[category];
}

export function getVerticalOrThrow(category: string): VerticalConfig {
  const v = VERTICALS[category];
  if (!v) throw new Error(`Unknown vertical: ${category}`);
  return v;
}

export function categoryLabel(category: string, lang: 'en' | 'fr'): string {
  return getVertical(category)?.label[lang] ?? category;
}

export function categoryLabelPlural(category: string, lang: 'en' | 'fr'): string {
  return getVertical(category)?.labelPlural[lang] ?? category;
}

// Map from old Category enum values to SubmissionCategory strings
export function normalizeCategory(input: string): string | null {
  const trimmed = input.trim();
  if (VERTICALS[trimmed]) return trimmed;
  // Legacy enum mappings
  const enumMap: Record<string, string> = {};
  for (const v of VERTICAL_LIST) {
    enumMap[v.enumKey] = v.category;
  }
  return enumMap[trimmed] ?? null;
}

// Gap label translation
export function gapLabel(gap: string, lang: 'en' | 'fr'): string {
  for (const v of VERTICAL_LIST) {
    for (const f of [...v.createFields, ...enrichableFieldDefs(v)]) {
      if (f.key === gap) return f.label[lang];
    }
  }
  return gap;
}
```

## 2. File-by-File Changes

### File 1: `shared/types.ts` (line 1)

**Current:** `export type SubmissionCategory = "pharmacy" | "fuel_station" | "mobile_money";`

**Change:** Replace the hardcoded union with a type derived from the registry.

```typescript
import { ALL_CATEGORIES } from './verticals.js';
export type SubmissionCategory = (typeof ALL_CATEGORIES)[number];
```

However, because `ALL_CATEGORIES` is a runtime array, TypeScript cannot narrow this to a literal union automatically. The pragmatic approach for an MVP: keep `SubmissionCategory` as `string` and rely on runtime validation from the registry. Alternatively, use a `const` assertion in verticals.ts:

```typescript
export const ALL_CATEGORIES = ['pharmacy', 'fuel_station', 'mobile_money'] as const;
export type SubmissionCategory = (typeof ALL_CATEGORIES)[number];
```

The `ALL_CATEGORIES` const tuple is derived from `Object.keys(VERTICALS)` at the type level via a helper, or simply maintained as a parallel const array that must match the registry keys. For an MVP, maintaining both is acceptable and explicit.

**No other changes** needed in `shared/types.ts` -- all the interfaces (`SubmissionDetails`, `PointEvent`, etc.) already use `SubmissionCategory` which will now widen as needed.

### File 2: `types.ts` (lines 15-19)

**Current:** Hardcoded `Category` enum.

**Change:** Derive from registry or deprecate. The `Category` enum is used purely on the client side for filtering. The simplest refactor:

```typescript
// Derive Category enum from registry
import { VERTICAL_LIST } from './shared/verticals';

// Keep as a plain object for backward compat with all the === comparisons
export const Category = Object.fromEntries(
  VERTICAL_LIST.map(v => [v.enumKey, v.enumKey])
) as Record<string, string>;
export type Category = string;
```

Or, keep the enum but generate it. Since enums are used pervasively with `===` comparisons, the cleanest approach is:

- Keep `Category` as a `Record<string, string>` object (acts like an enum).
- Add a `categoryToEnum(category: string): string` and `enumToCategory(enumKey: string): string` helper in `shared/verticals.ts`.
- All existing `Category.PHARMACY` references continue to work.

### File 3: `lib/server/pointProjection.ts`

**Current:** Hardcoded `ENRICHABLE_FIELDS`, `CREATE_REQUIRED_FIELDS`, and `normalizeDetailsForCategory()` with per-category `if` blocks.

**Changes:**

a) Replace `ENRICHABLE_FIELDS` and `CREATE_REQUIRED_FIELDS`:
```typescript
import { getVerticalOrThrow } from '../../shared/verticals.js';

// Delete the old ENRICHABLE_FIELDS and CREATE_REQUIRED_FIELDS objects.
// Replace usage sites:
function getEnrichableFields(category: string): readonly string[] {
  return getVerticalOrThrow(category).enrichableKeys;
}
function getCreateRequiredFields(category: string): readonly string[] {
  return getVerticalOrThrow(category).createRequiredKeys;
}
```

b) Refactor `normalizeDetailsForCategory()`: This is the hardest part. The per-category normalization logic (lines 77-131) contains business logic specific to mobile_money, fuel_station, and pharmacy. This logic cannot be fully data-driven without a plugin system.

**Strategy:** Keep `normalizeDetailsForCategory()` as-is for the three existing verticals. Add a fallback path for new verticals that applies generic normalization (trim strings, normalize booleans). The registry gets an optional `normalize` function, but for new verticals this defaults to a no-op because new verticals define their fields cleanly from the start.

```typescript
function normalizeDetailsForCategory(category: string, raw: SubmissionDetails): SubmissionDetails {
  const details: SubmissionDetails = { ...raw };
  // Common normalization
  const name = trimString(details.name) ?? trimString(details.siteName);
  if (name) { details.name = name; details.siteName = name; }
  const openingHours = trimString((details as any).opening_hours) ?? trimString(details.openingHours);
  if (openingHours) details.openingHours = openingHours;

  // Legacy vertical-specific normalization (keep existing logic)
  if (category === 'mobile_money') { /* existing block unchanged */ }
  if (category === 'fuel_station') { /* existing block unchanged */ }
  if (category === 'pharmacy') { /* existing block unchanged */ }

  // New verticals get generic normalization only (no special logic needed)
  return details;
}
```

This is deliberately pragmatic. New verticals won't need the same messy normalization because their field schemas will be clean from day one.

### File 4: `api/submissions/index.ts`

**Changes:**

a) Line 53 -- Replace `allowedCategories` array:
```typescript
import { ALL_CATEGORIES, normalizeCategory as normalizeCategoryFromRegistry } from '../../shared/verticals.js';
const allowedCategories = ALL_CATEGORIES;
```

b) Lines 112-120 -- Replace `normalizeCategory()`:
```typescript
function normalizeCategory(input: string | undefined): string | null {
  if (!input) return null;
  return normalizeCategoryFromRegistry(input);
}
```

This removes all the hardcoded `FUEL`, `MOBILE_MONEY`, `PHARMACY` mappings from the API layer. The registry's `normalizeCategory` handles them via `enumKey` lookups.

